"""Stub class for fairseq.data.dictionary.Dictionary.

The fairseq HuBERT checkpoint pickle references this class by name in
its task config. The actual Dictionary instance is part of cfg and
never used by ComfyUI-RVC's extract_feature_print.py; the class only
needs to exist by name so the unpickler can find it.

__setstate__ captures whatever attributes the pickle wants to restore;
__getattr__ returns None for missing access so any attribute lookup
on the restored instance is tolerant.
"""


class Dictionary:
    def __init__(self, *args, **kwargs):
        pass

    def __setstate__(self, state):
        if isinstance(state, dict):
            self.__dict__.update(state)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __reduce__(self):
        return (self.__class__, ())
